refsection.programlisting:
// Create example file
data = [1 2 3; 4 5 6; 7 8 9];
test_file = TMPDIR + "/test_sheet.xlsx";
xlsxWrite(data, test_file, "title", "My Report", "subject", "Data Analysis", ..
          "description", "Quarterly analysis results");

// Create a new sheet named "Data" at the end of the workbook
result = xlsxSheet(test_file, "create", "Data");

// Create a new sheet at position 2 (becomes the 2nd sheet)
result = xlsxSheet(test_file, "create", "Summary", 2);

// Delete a sheet by name
result = xlsxSheet(test_file, "delete", "Data");

// Delete a sheet by index (delete the 2nd sheet)
result = xlsxSheet(test_file, "delete", 2);

// Rename a sheet by name
result = xlsxSheet(test_file, "rename", "Sheet1", "NewData");

// Get information about all sheets in the workbook
info = xlsxSheet(test_file, "info")

// Get information about a specific sheet by index
info = xlsxSheet(test_file, "info", 1)
